# Fix CORS to allow dsm.4thandbailey.com
# Run: Set-ExecutionPolicy Bypass -Scope Process -Force; .\CORSFIX.ps1

$RepoPath = "C:\Users\LionelMosley\Documents\HTML\Synology - DiskStation Monitor"
Set-Location $RepoPath
Write-Host "Fixing CORS origins..." -ForegroundColor Cyan

$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
$fullPath = Join-Path $RepoPath "backend\src\index.ts"
[System.IO.File]::WriteAllBytes($fullPath, $bytes)
Write-Host "  wrote backend/src/index.ts" -ForegroundColor Green

git add backend/src/index.ts
git commit -m "fix: allow dsm.4thandbailey.com in CORS origins"
git push origin main

if ($LASTEXITCODE -eq 0) {
    Write-Host "`n✅ Pushed! Railway rebuilding with CORS fix." -ForegroundColor Green
    Write-Host "   After ~60 seconds, try signing in at https://dsm.4thandbailey.com/dsm-auth.html" -ForegroundColor Cyan
} else {
    Write-Host "`n❌ Push failed." -ForegroundColor Red
}